            (5.0, "live", "live-1", "A", "opportunity_ai_shadow"),
            (4.0, "live", "live-1", "A", "opportunity_ai_shadow"),
            (3.0, "live", "live-1", "A", "opportunity_ai_shadow"),
            (-35.0, "live", "live-1", "B", "opportunity_ai_shadow"),
